Create a 4-entry synchronous FIFO with combinational bypass.
`include "core_pkg.sv"
module fetch_queue (
  input  logic         clock,
  input  logic         reset,
  input  logic         flush,
  input  logic         push,
  input  if_id_t       push_data,
  input  logic         pop,
  output if_id_t       pop_data,
  output logic         full,
  output logic         empty
);
  if_id_t queue [0:3];
  logic [1:0] wptr, rptr;
  logic [2:0] count;

  assign empty = (count == 0) && !push;
  assign full  = (count == 4);
  assign pop_data = (count == 0) ? push_data : queue[rptr];

  always_ff @(posedge clock) begin
    if (reset || flush) begin
      wptr  <= '0;
      rptr  <= '0;
      count <= '0;
    end else begin
      if (push && !full && pop && !empty) begin
        queue[wptr] <= push_data;
        wptr <= wptr + 1;
        rptr <= rptr + 1;
      end else if (push && !full) begin
        queue[wptr] <= push_data;
        wptr <= wptr + 1;
        count <= count + 1;
      end else if (pop && !empty) begin
        rptr <= rptr + 1;
        count <= count - 1;
      end
    end
  end
endmodule

